@@ -2908,12 +2908,14 @@ impl PreparedStatement<'_> {
                     // the next read boundary instead of paying per-write mirror
                     // upkeep through the whole batch.
                     self.conn.memdb_storage_count_shortcuts_safe.set(false);
+                    self.conn.memdb_rows_loaded.set(false);
                     self.conn.memdb_requires_active_txn_reload.set(true);
                 } else {
                     self.conn
                         .memdb_storage_count_shortcuts_safe
                         .set(memdb_count_shortcuts_safe_after_exec);
                     if !memdb_count_shortcuts_safe_after_exec {
+                        self.conn.memdb_rows_loaded.set(false);
                         self.conn.memdb_requires_active_txn_reload.set(true);
                     }
                 }
@@ -3314,6 +3316,7 @@ impl PreparedStatement<'_> {
                 .memdb_storage_count_shortcuts_safe
                 .set(memdb_count_shortcuts_safe_after_exec);
             if !memdb_count_shortcuts_safe_after_exec {
+                self.conn.memdb_rows_loaded.set(false);
                 self.conn.memdb_requires_active_txn_reload.set(true);
             }
         }
@@ -18392,6 +18395,7 @@ impl Connection {
                                 // next read (SELECT). This avoids O(n²) behavior when
                                 // doing repeated autocommit INSERTs.
                                 self.memdb_storage_count_shortcuts_safe.set(false);
+                                self.memdb_rows_loaded.set(false);
                                 *self.memdb_visible_commit_seq.borrow_mut() = committed_seq;
                                 Ok(())
                             }
